   361→// ensureContentTypeHeader makes sure a content type always is returned in response.
   362→func ensureContentTypeHeader(res *backend.CallResourceResponse) {
   363→	if res == nil {
   364→		return
   365→	}
   366→
   367→	var hasContentType bool
   368→	for k := range res.Headers {
   369→		if textproto.CanonicalMIMEHeaderKey(k) == contentTypeHeaderName {
   370→			hasContentType = true
   371→			break
   372→		}
   373→	}
   374→
   375→	if !hasContentType && res.Status != http.StatusNoContent {
   376→		res.Headers[contentTypeHeaderName] = []string{defaultContentType}
   377→	}
   378→}
